rule.example:
class Bad {
    private val numFormat: DecimalFormat = DecimalFormat("###.###") // violation

    companion object {
        val NUMBER_FORMAT: DecimalFormat = DecimalFormat("###.###") // violation
    }
}

class Good {
    fun format(value: Double): String {
        val fmt = DecimalFormat("###.###") // ok: local variable
        return fmt.format(value)
    }
}

class Bar {        // poor, missing a hashCode() method
    override fun equals(o: Any?): Boolean {
      // do some comparison
    }
}

class Baz {        // poor, missing an equals() method
    override fun hashCode(): Int {
      // return some hash value
    }
}

class Foo {        // perfect, both methods provided
    override fun equals(other: Any?): Boolean {
      // do some comparison
    }
    override fun hashCode(): Int {
      // return some hash value
    }
}
